args.sqlite_command:
UPDATE J09B_temp
SET ENTSCHEIDUNG = (
  SELECT CASE WHEN COUNT(DISTINCT EQUNR) < 3 THEN 'KSA' ELSE 'EVU' END
  FROM J09B_temp t2
  WHERE t2.HAUS = J09B_temp.HAUS
);

